Here's the recommended approach using **Window lifecycle events** and `Preferences`:

**In `App.xaml.cs`** â€” override `CreateWindow` and hook `Stopped`, `Resumed`, and `Destroying`:

```csharp
public partial class App : Application
{
    protected override Window CreateWindow(IActivationState? activationState)
    {
        var window = base.CreateWindow(activationState);

        window.Stopped += (s, e) => SaveDraft();
        window.Resumed += (s, e) => RestoreDraft();
        window.Destroying += (s, e) => SaveDraft(); // Android back-button skips Stopped

        return window;
    }

    private void SaveDraft()
    {
        if (Current?.MainPage is AppShell shell)
        {
            var vm = shell.GetCurrentViewModel<NoteViewModel>();
            if (vm != null)
                Preferences.Set("draft_text", vm.DraftText);
        }
    }

    private void RestoreDraft()
    {
        if (Current?.MainPage is AppShell shell)
        {
            var vm = shell.GetCurrentViewModel<NoteViewModel>();
            if (vm != null)
                vm.DraftText = Preferences.Get("draft_text", string.Empty);
        }
    }
}
```

Or **simpler** â€” keep it self-contained in a custom `Window` subclass:

```csharp
public class AppWindow : Window
{
    private readonly NoteViewModel _vm;

    public AppWindow(Page page, NoteViewModel vm) : base(page) => _vm = vm;

    protected override void OnStopped()
    {
        base.OnStopped();
        Preferences.Set("draft_text", _vm.DraftText);
    }

    protected override void OnResumed()
    {
        base.OnResumed();
        _vm.DraftText = Preferences.Get("draft_text", string.Empty);
    }

    protected override void OnDestroying()
    {
        base.OnDestroying();
        Preferences.Set("draft_text", _vm.DraftText);
    }
}
```

### Key points

| Rule | Why |
|---|---|
| Save in **both** `OnStopped` and `OnDestroying` | Android back-button can skip `Stopped` entirely |
| `Resumed` does **not** fire on first launch | Load initial draft in your page/VM constructor, not here |
| Keep handlers **fast** (<1-2s) | Android ANR timeout and iOS watchdog will kill slow handlers |
| Use `Preferences` for small strings | It's synchronous and fast â€” ideal for draft text |

For larger state (images, rich documents), serialize to a file instead of `Preferences`.
